"""SSRF policy e2e tests — verifies that loopback and private-network URLs
are rejected before any TCP connect attempt."""

import pytest
from kreuzcrawl import create_engine, scrape

# Port 9 (discard) is deliberately chosen: SSRF policy rejects the URL
# before any TCP connection attempt, so the test does not depend on
# a listening server.
_LOOPBACK_URL = "http://127.0.0.1:9/"
_PRIVATE_URL = "http://10.0.0.1:9/"


@pytest.mark.asyncio
async def test_ssrf_loopback_denied_by_default() -> None:
    """Default config rejects loopback URLs before any network connect."""
    with pytest.raises(Exception) as exc_info:  # noqa: B017
        engine = create_engine(None)
        await scrape(engine, _LOOPBACK_URL)
    assert "ssrf_policy_violation" in str(exc_info.value)  # noqa: S101


@pytest.mark.asyncio
async def test_ssrf_private_network_class_a_denied() -> None:
    """Default config rejects RFC-1918 class-A addresses (10.x.x.x)."""
    with pytest.raises(Exception) as exc_info:  # noqa: B017
        engine = create_engine(None)
        await scrape(engine, _PRIVATE_URL)
    assert "ssrf_policy_violation" in str(exc_info.value)  # noqa: S101
